// Register new users
function register_new_user() {
    $username = $_POST['username'];
    $password = $_POST['password'];
    
    // Hash the password
    $hashed_password = password_hash($password, PASSWORD_DEFAULT);
    
    // Insert user into database
    $userdata = array(
        'user_login' => $username,
        'user_pass' => $hashed_password,
        'user_email' => '',
        'role' => 'subscriber'
    );
    wp_insert_user($userdata);
    
    echo "User registered successfully!";
}
add_action('wp_ajax_nopriv_register_new_user', 'register_new_user'); // For logged-out users
add_action('wp_ajax_register_new_user', 'register_new_user'); // For logged-in users

// User login authentication
function user_login() {
    $username = $_POST['username'];
    $password = $_POST['password'];
    
    // Authenticate the user
    $user = get_user_by('login', $username);
    
    if ($user && wp_check_password($password, $user->data->user_pass, $user->ID)) {
        echo "User authenticated successfully!";
    } else {
        echo "Invalid username or password.";
    }
}
add_action('wp_ajax_nopriv_user_login', 'user_login'); // For logged-out users
add_action('wp_ajax_user_login', 'user_login'); // For logged-in users
